import { useEffect, useMemo, useRef, useState } from "react";

// Define los colores para fácil acceso
const navy = '#072d42';
const beige = '#F4E9D7';

export default function Index() {
  const sections = useMemo(
    () => [
      {
        id: "objective",
        title: "OBJECTIVE",
        body: (
          <p>
            Orbis Empresarial preserves, organizes, and showcases the corporate heritage of Bolivian
            companies with more than 40 years of trajectory. We digitize archives, certify milestones,
            and curate living narratives that honor legacy while inspiring the next generation of leaders.
          </p>
        ),
      },
      {
        id: "mission",
        title: "MISSION",
        body: (
          <p>
            To protect the memory of Bolivian enterprise through rigorous documentation, thoughtful
            storytelling, and timeless design—making each company's journey accessible, verifiable, and
            beautifully preserved for the future.
          </p>
        ),
      },
      {
        id: "vision",
        title: "VISION",
        body: (
          <p>
            A prestigious national archive where the history of business excellence is treasured—
            a reference for researchers, entrepreneurs, and families that elevates the legacy of
            Bolivian industry on the world stage.
          </p>
        ),
      },
      {
        id: "origin",
        title: "ORIGIN",
        body: (
          <p>
            Born from a commitment to cultural memory, Orbis Empresarial emerged when historians,
            archivists, and innovators united around a single idea: if we don't document our
            enterprises today, tomorrow's generations will inherit silence where there should be legacy.
          </p>
        ),
      },
      {
        id: "how",
        title: "HOW IT STARTED",
        body: (
          <div className="w-full">
            <div className="relative overflow-x-auto md:overflow-visible px-2 py-6">
              <div
                className="absolute left-6 right-6 md:left-8 md:right-8 top-1/2 -translate-y-1/2 h-[1px] rounded-full"
                style={{ background: `linear-gradient(to right, transparent, ${navy}40, transparent)` }}
              />
              <ol className="relative z-10 flex min-w-[640px] md:min-w-0 items-start gap-10 md:gap-12 lg:gap-16 px-4 md:px-8 snap-x">
                {[
                  { year: "1980s", text: "Foundational archives collected across departments." },
                  { year: "1990s", text: "First private–public preservation partnerships." },
                  { year: "2000s", text: "Digitization program and certification standards." },
                  { year: "2010s", text: "Interactive exhibits and institutional expansion." },
                  { year: "Today", text: "A living platform connecting legacy with innovation." },
                ].map((m) => (
                  <li key={m.year} className="snap-center min-w-[160px]">
                    <div className="flex flex-col items-center text-center gap-3">
                      <div className="relative">
                        <span className="block w-2 h-2 rounded-full" style={{ backgroundColor: navy }} />
                      </div>
                      <div className="text-sm font-light tracking-wide">
                        <span className="font-serif text-lg block mb-1" style={{color: navy}}>{m.year}</span>
                        <span className="block max-w-[16rem] text-xs leading-tight" style={{ color: navy, opacity: 0.8 }}>{m.text}</span>
                      </div>
                    </div>
                  </li>
                ))}
              </ol>
            </div>
          </div>
        ),
      },
    ],
    [],
  );

  const [active, setActive] = useState(sections[0].id);
  const [visible, setVisible] = useState({});
  const refs = useRef({});

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        let best = { id: active, ratio: 0 };
        entries.forEach((entry) => {
          const id = entry.target.id;
          if (entry.isIntersecting) {
            setVisible((prev) => ({ ...prev, [id]: true }));
          }
          if (entry.intersectionRatio > best.ratio) {
            best = { id, ratio: entry.intersectionRatio };
          }
        });
        if (best.id) setActive(best.id);
      },
      { root: null, threshold: [0.25, 0.5, 0.75], rootMargin: "-20% 0px -40% 0px" },
    );

    sections.forEach((s) => {
      const el = refs.current[s.id];
      if (el) observer.observe(el);
    });
    return () => observer.disconnect();
  }, []);

  const scrollTo = (id) => {
    const el = refs.current[id];
    if (!el) return;
    
    const elementPosition = el.getBoundingClientRect().top + window.pageYOffset;
    const offsetPosition = elementPosition - 100;
    
    window.scrollTo({
      top: offsetPosition,
      behavior: "smooth"
    });
    setActive(id);
  };

  return (
    <div style={{ backgroundColor: beige, color: navy, minHeight: '100vh', fontFamily: 'Arial, sans-serif' }}>
      <main className="mx-auto max-w-5xl px-6 py-12">
        {/* Header exacto como en la imagen */}
        <div className="text-left mb-16">
          <h1 className="font-serif text-5xl lg:text-6xl font-normal leading-tight tracking-tight mb-4" style={{ color: navy }}>
            Orbis<br />Empresarial
          </h1>
          <div className="h-px w-20 mb-6" style={{ backgroundColor: navy }}></div>
          <p className="text-lg font-light tracking-wide max-w-md" style={{ color: navy, opacity: 0.9 }}>
            Preserving the living history of Bolivian companies 40+ years strong.
          </p>
        </div>

        <div className="flex flex-col lg:flex-row gap-16">
          {/* Navegación lateral minimalista */}
          <aside className="lg:w-1/4">
            <nav className="flex lg:flex-col gap-1">
              {sections.map((s) => (
                <button
                  key={s.id}
                  onClick={() => scrollTo(s.id)}
                  className={`text-left py-3 px-1 transition-all duration-300 border-b lg:border-b-0 lg:border-l-2 ${
                    active === s.id ? 'font-medium' : 'font-light opacity-70'
                  }`}
                  style={{ 
                    borderColor: active === s.id ? navy : `${navy}30`,
                    color: navy
                  }}
                >
                  <span className="tracking-widest text-sm">{s.title}</span>
                </button>
              ))}
            </nav>
          </aside>

          {/* Contenido principal */}
          <section className="lg:w-3/4 flex flex-col gap-20">
            {sections.map((s, idx) => (
              <div
                key={s.id}
                id={s.id}
                ref={(el) => (refs.current[s.id] = el)}
                className="scroll-mt-20"
              >
                <div
                  className={`transition-opacity duration-700 ${
                    visible[s.id] ? "opacity-100" : "opacity-70"
                  }`}
                >
                  {/* Encabezado de sección */}
                  <div className="mb-8">
                    <h2 
                      className="font-serif text-3xl font-normal mb-4 tracking-wide"
                      style={{ color: navy }}
                    >
                      {s.title.replace('OBJECTIVE', 'Objective').replace('MISSION', 'Mission').replace('VISION', 'Vision').replace('ORIGIN', 'Origin').replace('HOW IT STARTED', 'How It Started')}
                    </h2>
                    <div className="h-px w-16" style={{ backgroundColor: navy }}></div>
                  </div>

                  {/* Contenido */}
                  <div>
                    <div 
                      className="text-lg leading-relaxed font-light tracking-wide"
                      style={{ color: navy, opacity: 0.95 }}
                    >
                      {s.body}
                    </div>
                  </div>
                </div>

                {/* Línea separadora sutil */}
                {idx !== sections.length - 1 && (
                  <div className="mt-20 h-px" style={{ background: `linear-gradient(to right, transparent, ${navy}20, transparent)` }} />
                )}
              </div>
            ))}
          </section>
        </div>

        {/* Footer minimalista */}
        <footer className="mt-24 pt-8 border-t text-center" style={{ borderColor: `${navy}20` }}>
          <p className="text-sm font-light tracking-wide" style={{ color: navy, opacity: 0.6 }}>
            © {new Date().getFullYear()} Orbis Empresarial
          </p>
        </footer>
      </main>

      <style jsx>{`
        .font-serif {
          font-family: 'Georgia', 'Times New Roman', serif;
        }
      `}</style>
    </div>
  );
}
